    long long n = prices.size();
    long long original_profit = 0;
    for (long long i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    long long max_profit = original_profit;
    long long half_k = k / 2;

    vector<long long> prefix(n + 1, 0);
    for (long long i = 0; i < n; ++i) {
        prefix[i + 1] = prefix[i] + strategy[i] * prices[i];
    }

    vector<long long> window_zero_sum(n + 1, 0);
    for (long long i = 0; i < n; ++i) {
        window_zero_sum[i + 1] = window_zero_sum[i] + (0 - strategy[i]) * prices[i];
    }

    vector<long long> window_one_sum(n + 1, 0);
    for (long long i = 0; i < n; ++i) {
        window_one_sum[i + 1] = window_one_sum[i] + (1 - strategy[i]) * prices[i];
    }

    for (long long i = 0; i <= n - k; ++i) {
        long long j = i + k;
        long long zero_part = window_zero_sum[i + half_k] - window_zero_sum[i];
        long long one_part = window_one_sum[j] - window_one_sum[i + half_k];
        long long total = original_profit + zero_part + one_part;
        if (total > max_profit) {
            max_profit = total;
        }
    }

    return max_profit;
}

