def solve(prices: Array[Long], strategy: Array[Long], k: Long): Long = {
    val n = prices.length
    val originalProfit = (0 until n).map(i => strategy(i) * prices(i)).sum

    var maxProfit = originalProfit
    val halfK = (k / 2).toInt

    val prefix = Array.ofDim[Long](n + 1)
    for (i <- 0 until n) {
        prefix(i + 1) = prefix(i) + strategy(i) * prices(i)
    }

    val windowZeroSum = Array.ofDim[Long](n + 1)
    for (i <- 0 until n) {
        windowZeroSum(i + 1) = windowZeroSum(i) + (0 - strategy(i)) * prices(i)
    }

    val windowOneSum = Array.ofDim[Long](n + 1)
    for (i <- 0 until n) {
        windowOneSum(i + 1) = windowOneSum(i) + (1 - strategy(i)) * prices(i)
    }

    for (i <- 0 to n - k.toInt) {
        val j = i + k.toInt
        val zeroPart = windowZeroSum(i + halfK) - windowZeroSum(i)
        val onePart = windowOneSum(j) - windowOneSum(i + halfK)
        val total = originalProfit + zeroPart + onePart
        if (total > maxProfit) {
            maxProfit = total
        }
    }

    maxProfit
}
